Generate a Python code to print all the permutations of an array.

### Response:
def permutation(arr):
    if not arr:
        return []
    elif len(arr) == 1:
        return [arr]
    else:
        l = []
        for i in range(len(arr)):
            data = arr[i]
            remainders = arr[:i] + arr[i+1:]
            for p in permutation(remainders):
                l.append([data] + p)
        return l

