def find_min_coins(amount, denominations):
    min_coins = [float("inf")] * (amount + 1)
    min_coins[0] = 0

    for i in range(1, amount + 1):
        for c in denominations:
            if i - c >= 0:
                min_coins[i] = min(min_coins[i - c] + 1, min_coins[i])

